import type {
  BillingAddressInput,
  ShippingAddressInput,
} from '@/checkout/data/models/api';
import type { CartAddress } from '@/checkout/data/models/cart';

export const transformAddressFormValuesToAddressInput = (
  data: Record<string, any>
): ShippingAddressInput | BillingAddressInput => {
  const isNewAddress = !data?.id && !data?.uid;

  if (!isNewAddress) {
    return {
      customerAddressId: data.id,
      customerAddressUid: data.uid,
    };
  }

  const customAttributes = data.customAttributes?.map(
    ({ code, value }: { code: string; value: unknown }) => ({
      code,
      value: String(value),
    })
  );

  return {
    address: {
      city: data.city,
      company: data?.company,
      countryCode: data.countryCode,
      customAttributes,
      fax: data.fax,
      firstName: data.firstName,
      lastName: data.lastName,
      middleName: data.middleName,
      postcode: data.postcode,
      prefix: data.prefix,
      region: data?.region?.regionCode,
      regionId: data?.region?.regionId,
      street: data.street,
      suffix: data.suffix,
      telephone: data.telephone,
      vatId: data.vatId,
      saveInAddressBook: data.saveAddressBook,
    },
  };
};

export const transformCartAddressToFormValues = (
  address: CartAddress
): Record<string, any> => {
  return {
    city: address.city,
    company: address?.company,
    countryCode: address.country?.code,
    customAttributes: address.customAttributes,
    fax: address.fax,
    firstName: address.firstName,
    lastName: address.lastName,
    middleName: address.middleName,
    postcode: address.postCode,
    prefix: address.prefix,
    region: {
      regionCode: address.region?.code,
      regionId: address.region?.id,
    },
    street: address.street,
    suffix: address.suffix,
    telephone: address.telephone,
    vatId: address.vatId,
  };
};
