import { scrollToParentContainer } from '@/checkout/lib/utils/dom';
import type { FormRef } from '@/checkout/types';
import { RefObject } from 'preact';

type HTMLForm = {
  name: string;
  ref?: RefObject<FormRef>;
};

export function validateForm(
  form: HTMLForm,
  autoScrollOnError: boolean = false
): boolean {
  const { name, ref } = form;
  const formElement = document.forms.namedItem(name);

  if (!formElement || formElement.offsetParent === null) {
    return true;
  }

  formElement.setAttribute('novalidate', '');

  const validationResult =
    ref?.current?.handleValidationSubmit(false) ?? formElement.checkValidity();

  if (!validationResult && autoScrollOnError) {
    scrollToParentContainer(formElement);
  }

  return validationResult;
}

export function validateForms(forms: HTMLForm[]): boolean {
  for (const form of forms) {
    if (!validateForm(form, true)) {
      return false;
    }
  }
  return true;
}
