import {
  estimateShippingMethods,
  setBillingAddress,
  setShippingAddress,
} from '@/checkout/api';
import type {
  BillingAddressInput,
  ShippingAddressInput,
} from '@/checkout/data/models/api';
import { transformAddressFormValuesToAddressInput } from '@/checkout/lib/utils/transformers';
import { debounce } from '@adobe-commerce/elsie/lib';
import { isSetAddressRequestPending } from '@/checkout/store/ui';

type AddressFormChange = {
  data: Record<string, any>;
  isDataValid: boolean;
};

let ongoingSetAddressCalls = 0;

export function setAddressOnCart({
  type = 'shipping',
  debounceMs = 0,
}: {
  type?: 'shipping' | 'billing';
  debounceMs?: number;
}) {
  const api = type === 'shipping' ? setShippingAddress : setBillingAddress;

  const debouncedApi = debounce(
    (address: ShippingAddressInput | BillingAddressInput) => {
      ongoingSetAddressCalls += 1;
      api(address)
        .catch(console.error)
        .finally(() => {
          ongoingSetAddressCalls -= 1;
          if (ongoingSetAddressCalls === 0) {
            isSetAddressRequestPending.value = false;
          }
        });
    },
    debounceMs
  );

  return ({ data, isDataValid }: AddressFormChange) => {
    if (!isDataValid) return;
    isSetAddressRequestPending.value = true;
    const address = transformAddressFormValuesToAddressInput(data);
    debouncedApi(address);
  };
}

export function estimateShippingCost({ debounceMs = 0 }) {
  let prevEstimateShippingData: {
    countryCode?: string;
    regionCode?: string;
    regionId?: string;
    postcode?: string;
  } = {};

  let shouldCancelDebounce = false;

  const debouncedApi = debounce((data: Record<string, any>) => {
    if (shouldCancelDebounce) return;

    const estimateShippingInputCriteria = {
      country_code: data.countryCode,
      region_name: String(data.region?.regionCode || ''),
      region_id: String(data.region?.regionId || ''),
      zip: data.postcode,
    };

    estimateShippingMethods({ criteria: estimateShippingInputCriteria });

    prevEstimateShippingData = {
      countryCode: data.countryCode,
      regionCode: data.region?.regionCode || '',
      regionId: data.region?.regionId || '',
      postcode: data.postcode,
    };
  }, debounceMs);

  return ({ data, isDataValid }: AddressFormChange) => {
    if (isDataValid) {
      shouldCancelDebounce = true;
      return;
    }

    if (
      prevEstimateShippingData.countryCode === data.countryCode &&
      prevEstimateShippingData.regionCode === (data.region?.regionCode || '') &&
      prevEstimateShippingData.regionId === (data.region?.regionId || '') &&
      prevEstimateShippingData.postcode === data.postcode
    )
      return;

    debouncedApi(data);
  };
}
