export function createMetaTag(property: string, content: string, type: string) {
  if (!property || !type) {
    return;
  }

  const meta = document.head.querySelector<HTMLMetaElement>(
    `meta[${type}="${property}"]`
  );

  if (!content) {
    meta?.remove();
    return;
  }

  if (meta) {
    meta.setAttribute('content', content);
  } else {
    const newMeta = document.createElement('meta');
    newMeta.setAttribute(type, property);
    newMeta.setAttribute('content', content);
    document.head.appendChild(newMeta);
  }
}

export function setMetaTags(dropin: string) {
  createMetaTag('title', dropin, 'name');
  createMetaTag('description', dropin, 'name');
  createMetaTag('keywords', dropin, 'name');
  createMetaTag('og:description', dropin, 'property');
  createMetaTag('og:title', dropin, 'property');
  createMetaTag('og:url', window.location.href, 'property');
}
